import { HttpClient } from "@angular/common/http";
import { Component, OnInit, ViewChild } from "@angular/core";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { AlertController } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { Job } from "src/app/views/Models/Users/Job";
import { format, getMonth, parse } from "date-fns";
import { TranslateService } from "@ngx-translate/core";
import { Tree } from "src/app/views/Models/Users/Tree";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
import { TreeComponent } from "src/app/views/components/tree/tree.component";
import { JobsService } from "src/app/core/services/jobs.service";

@Component({
  selector: "app-job-management",
  templateUrl: "./job-management.page.html",
  styleUrls: ["./job-management.page.scss"],
})
export class JobManagementPage implements OnInit {
  @ViewChild("appFoo") appFoo: TreeComponent<Job>;
  showLoader: boolean = false;
  isInsertingJob: boolean = false;
  isEditingJob: boolean = false;
  canEdit?: boolean = true;
  canAdd?: boolean = true;
  canDelete?: boolean = true;

  hasSupervisor: boolean = false;

  sortingIconClass: string;
  sortingIconParam: string;

  jobs: Job[];
  FilteredJobs: Job[];
  jobInfo: Job;
  org_code;

  jobTypes: StaticRef[] = [];

  days: string[][];

  jobHierarchy: Tree<Job>[];

  constructor(
    private http: HttpClient,
    private formBuilder: FormBuilder,
    private alertController: AlertController,
    private env: EnvService,
    private authService: MohassilAuthService,
    private sortingService: sortingService,
    private alertServices: AlertService,
    public translate: TranslateService,
    public inputMaskingService: InputMaskingService,
    private jobsService: JobsService
  ) {}

  JobForm: FormGroup;

  async ngOnInit() {
    this.days = [
      [await this.translate.get("days.saturday").toPromise(), "saturday"],
      [await this.translate.get("days.sunday").toPromise(), "sunday"],
      [await this.translate.get("days.monday").toPromise(), "monday"],
      [await this.translate.get("days.tuesday").toPromise(), "tuesday"],
      [await this.translate.get("days.wednesday").toPromise(), "wednesday"],
      [await this.translate.get("days.thursday").toPromise(), "thursday"],
      [await this.translate.get("days.friday").toPromise(), "friday"],
    ];
    await this.authService.getUserInfo().then((userInfo) => {
      this.org_code = userInfo.org_code;
    });
    this.GetJobTypes();
    this.GetAllJobs();
    this.JobForm = this.formBuilder.group({
      job_name: ["", [Validators.required, this.noWhitespaceValidator]],
      job_type: ["", [Validators.required, this.noWhitespaceValidator]],
      supervisor_id: [null],
      max_no_users: ["", [Validators.required, this.noWhitespaceValidator]],
      startTime: ["00:00", [Validators.required]],
      endTime: ["23:59", [Validators.required]],
      workingDays: [
        ["sunday", "monday", "tuesday", "wednesday", "thursday"],
        [Validators.required],
      ],
      saturday: [0],
      sunday: [1],
      monday: [1],
      tuesday: [1],
      wednesday: [1],
      thursday: [1],
      friday: [0],
    });
  }

  clearForms() {
    this.isInsertingJob = false;
    this.isEditingJob = false;
    this.JobForm.reset();
    this.JobForm.patchValue({
      startTime: "00:00",
      endTime: "23:59",
      workingDays: ["sunday", "monday", "tuesday", "wednesday", "thursday"],
    });
  }

  InsertJob() {
    this.isInsertingJob = true;
    this.FilteredJobs = this.jobs;

    if (this.JobForm.value.supervisor_id) this.hasSupervisor = true;
    else this.hasSupervisor = false;
  }
  GetJobTypes() {
    this.http
      .get<StaticRef[]>(this.env.API_URL + "api/StaticRef/GetJobTypes")
      .subscribe({
        next: (data) => {
          this.jobTypes = data;
        },
        error: (err) => {
          console.log(err);
        },
      });
  }
  async GetAllJobs() {
    this.showLoader = true;
    this.jobHierarchy = await this.jobsService.getJobsTree();
    this.showLoader = false;
  }

  GetAllJobSupervisors(job_id) {
    this.showLoader = true;
    this.http
      .post<Job[]>(this.env.API_URL + "api/Job/GetAllJobSupervisors", {
        org_code: this.org_code,
        // job_id: this.jobs[index].job_id.toString(),
        job_id: job_id.toString(),
      })
      .subscribe({
        next: (data) => {
          this.FilteredJobs = data;
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }

  GetJobByID(job_id, isEditingJob) {
    // this.showLoader = true;
    this.http
      .post<Job>(this.env.API_URL + "api/Job/GetJobByID", {
        org_code: this.org_code.toString(),
        // job_id: this.jobs[index].job_id.toString(),
        job_id: job_id,
      })
      .subscribe({
        next: (data) => {
          console.log(data);
          this.jobInfo = data;
          if (isEditingJob) this.patchJobDataValue(this.jobInfo);
          if (isEditingJob) this.GetAllJobSupervisors(job_id);
          // this.FilteredJobs = this.jobs.filter(
          //   (job) =>
          //     (job.supervisor_id == null &&
          //       this.jobInfo.job_id != job.job_id) ||
          //     (parseInt(job.supervisor_id) < parseInt(this.jobInfo.job_id) &&
          //       parseInt(job.job_id) != parseInt(this.jobInfo.job_id))
          // );
          // console.log(this.FilteredJobs);
          this.isEditingJob = isEditingJob;
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }

  async GetWorkingDays() {
    let workingDays = this.JobForm.value.workingDays;

    let saturday = workingDays.find((x) => x === "saturday");
    let sunday = workingDays.find((x) => x === "sunday");
    let monday = workingDays.find((x) => x === "monday");
    let tuesday = workingDays.find((x) => x === "tuesday");
    let wednesday = workingDays.find((x) => x === "wednesday");
    let thursday = workingDays.find((x) => x === "thursday");
    let friday = workingDays.find((x) => x === "friday");

    this.JobForm.patchValue({
      saturday: saturday != undefined ? 1 : 0,
      sunday: sunday != undefined ? 1 : 0,
      monday: monday != undefined ? 1 : 0,
      tuesday: tuesday != undefined ? 1 : 0,
      wednesday: wednesday != undefined ? 1 : 0,
      thursday: thursday != undefined ? 1 : 0,
      friday: friday != undefined ? 1 : 0,
    });
    console.log(this.JobForm.value);
  }

  async SubmitJob() {
    if (this.JobForm.valid) {
      this.showLoader = true;
      let supervisor_id;
      if (this.JobForm.value.supervisor_id != null) {
        supervisor_id =
          this.JobForm.value.supervisor_id == ""
            ? null
            : this.JobForm.value.supervisor_id.toString();
      }
      await this.GetWorkingDays();
      this.http
        .post(this.env.API_URL + "api/Job/CreateJob", {
          org_code: this.org_code.toString(),
          job_name: this.JobForm.value.job_name.toString(),
          job_type: this.JobForm.value.job_type.toString(),
          supervisor_id: supervisor_id,
          max_no_users: this.JobForm.value.max_no_users.toString(),
          start_time: this.JobForm.value.startTime.toString(),
          end_time: this.JobForm.value.endTime.toString(),
          saturday: this.JobForm.value.saturday,
          sunday: this.JobForm.value.sunday,
          monday: this.JobForm.value.monday,
          tuesday: this.JobForm.value.tuesday,
          wednesday: this.JobForm.value.wednesday,
          thursday: this.JobForm.value.thursday,
          friday: this.JobForm.value.friday,
        })
        .subscribe({
          next: (data) => {
            this.showLoader = false;
            this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
          },
          error: (err) => {
            console.log(err);
            this.alertServices.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }

  async EditJob() {
    if (this.JobForm.valid) {
      if (
        await this.alertServices.SaveAlert(
          "هل انت متاكد من تغيير بيانات الوظيفة؟"
        )
      ) {
        this.showLoader = true;
        await this.GetWorkingDays();
        this.http
          .post(this.env.API_URL + "api/Job/EditJob", {
            org_code: this.org_code.toString(),
            job_id: this.jobInfo.job_id.toString(),
            job_name: this.JobForm.value.job_name.toString(),
            job_type: this.jobInfo.job_type,
            supervisor_id:
              this.JobForm.value.supervisor_id == "" ||
              !this.JobForm.value.supervisor_id
                ? null
                : this.JobForm.value.supervisor_id.toString(),
            max_no_users: this.JobForm.value.max_no_users.toString(),
            start_time: this.JobForm.value.startTime.toString(),
            end_time: this.JobForm.value.endTime.toString(),
            saturday: this.JobForm.value.saturday,
            sunday: this.JobForm.value.sunday,
            monday: this.JobForm.value.monday,
            tuesday: this.JobForm.value.tuesday,
            wednesday: this.JobForm.value.wednesday,
            thursday: this.JobForm.value.thursday,
            friday: this.JobForm.value.friday,
          })
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }

  async DeleteJob(job_id: number, org_code: number) {
    if (
      await this.alertServices.DeleteAlert("هل انت متاكد من مسح هذه الوظيفة؟")
    ) {
      this.showLoader = true;
      this.http
        .post(this.env.API_URL + "api/Job/DeleteJob", {
          // org_code: this.jobs[index].org_code.toString(),
          // job_id: this.jobs[index].job_id.toString(),
          org_code: org_code,
          job_id: job_id,
        })
        .subscribe({
          next: (data) => {
            this.showLoader = false;
            this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
          },
          error: (err) => {
            console.log(err);
            this.alertServices.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }

  patchJobDataValue(job: Job) {
    let days: string[];

    days = this.days.map((d) => d[1]).filter((d) => job[d] == 1);
    console.log(job);
    this.JobForm.patchValue({
      job_name: job.job_name,
      job_type: job.job_type + "",
      supervisor_id: job.supervisor_id,
      max_no_users: job.max_no_users,
      startTime: job.start_time,
      endTime: job.end_time,
      workingDays: days,
    });
  }

  noWhitespaceValidator(control: FormControl) {
    const isWhitespace =
      control.value !== null &&
      (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }

  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }

  Edit(node: Tree<Job>): void {
    this.hasSupervisor = false;
    this.GetJobByID(node.data.job_id, true);
  }

  Delete(node: Tree<Job>): void {
    this.DeleteJob(node.data.job_id, node.data.org_code);
  }

  Add(node: Tree<Job>): void {
    this.GetJobByID(node.data.job_id, false);
    this.JobForm.patchValue({
      supervisor_id: node.data.job_id,
    });
    this.hasSupervisor = true;

    this.InsertJob();
    console.log(this.isEditingJob, this.isInsertingJob);
  }
}
